class Solution:
    def subsequenceSumAfterCapping(self, nums, k):
        n = len(nums)
        ans = []
        for x in range(1, n + 1):
            reach = 1  # bitmask of reachable sums
            for v in nums:
                w = v if v < x else x
                reach |= reach << w
                reach &= (1 << (k + 1)) - 1
            ans.append(bool((reach >> k) & 1))
        return ans

