class Solution:
    def subsequenceSumAfterCapping(self, nums, k):
        from collections import Counter
        n = len(nums)
        cnt = Counter(nums)
        dp = [False] * (k + 1)
        dp[0] = True
        ans = []
        cum_le = 0
        for x in range(1, n + 1):
            c = cnt.get(x, 0)
            for _ in range(c):
                for s in range(k, x - 1, -1):
                    if dp[s - x]:
                        dp[s] = True
            cum_le += c
            big = n - cum_le
            ok = False
            j = 0
            while j * x <= k and j <= big:
                if dp[k - j * x]:
                    ok = True
                    break
                j += 1
            ans.append(ok)
        return ans

