var subsequenceSumAfterCapping = function(nums, k) {
    const n = nums.length;
    const cnt = new Map();
    for (const v of nums) cnt.set(v, (cnt.get(v) || 0) + 1);
    const dp = new Array(k + 1).fill(false);
    dp[0] = true;
    const ans = [];
    let cumLe = 0;
    for (let x = 1; x <= n; x++) {
        const c = cnt.get(x) || 0;
        for (let t = 0; t < c; t++) {
            for (let s = k; s >= x; s--) {
                if (dp[s - x]) dp[s] = true;
            }
        }
        cumLe += c;
        const big = n - cumLe;
        let ok = false;
        let j = 0;
        while (j * x <= k && j <= big) {
            if (dp[k - j * x]) { ok = true; break; }
            j++;
        }
        ans.push(ok);
    }
    return ans;
};
